#!/bin/bash

# Deploy script for Carbon Helpdesk frontend updates
# This script deploys 4 frontend files and rebuilds the container

set -e

REMOTE_HOST="143.198.20.6"
REMOTE_USER="root"
REMOTE_PATH="/opt/carbon-helpdesk"

echo "Connecting to $REMOTE_HOST as $REMOTE_USER..."
echo "You will be prompted for the password"

# Create a temporary SSH command script
TEMP_SCRIPT=$(mktemp)
trap "rm -f $TEMP_SCRIPT" EXIT

cat > "$TEMP_SCRIPT" << 'EOF'
#!/bin/bash
set -e

# Decode and write Sidebar.jsx
echo "Deploying Sidebar.jsx..."
cat << 'SIDEBAR_B64' | base64 -d > /opt/carbon-helpdesk/frontend/src/components/Sidebar.jsx

SIDEBAR_B64

# Decode and write SettingsPage.jsx
echo "Deploying SettingsPage.jsx..."
cat << 'SETTINGS_B64' | base64 -d > /opt/carbon-helpdesk/frontend/src/pages/SettingsPage.jsx

SETTINGS_B64

# Decode and write TicketsPage.jsx
echo "Deploying TicketsPage.jsx..."
cat << 'TICKETS_B64' | base64 -d > /opt/carbon-helpdesk/frontend/src/pages/TicketsPage.jsx

TICKETS_B64

# Decode and write index.css
echo "Deploying index.css..."
cat << 'INDEX_B64' | base64 -d > /opt/carbon-helpdesk/frontend/src/index.css

INDEX_B64

echo "All files deployed successfully!"

# Rebuild and restart container
echo "Rebuilding and restarting frontend container..."
cd /opt/carbon-helpdesk
docker compose up -d --build frontend

echo "Deployment complete!"
EOF

# SSH and execute
ssh -t "$REMOTE_USER@$REMOTE_HOST" bash < "$TEMP_SCRIPT"

echo "Frontend update deployment finished successfully!"

